body:
## Problem

Random lines are not drawn for a fraction of a second when editing a file. Line above is partially cut off. Contents below, including cursor line, are shifted one line up and then down.

https://github.com/user-attachments/assets/0ef1b751-529d-421c-9d50-dd69e99319cc

Originally reported at (https://github.com/neovim/neovim/issues/33205), but I debugged it more and I think this is an issue in neovim-qt.

## Cause

The [UI protocol docs](https://github.com/neovim/neovim/blob/f027f41e2cfba7be8c4841cb1a036827375bbd73/runtime/doc/api-ui-events.txt#L99-L105) specify that update events within a `redraw` batch should only be displayed after a `flush` event. 

Currently, neovim-qt applies each update immediately ([shell.cpp](https://github.com/equalsraf/neovim-qt/blob/99d26d355545e7241a0b74586cccd636c88629fc/src/gui/shell.cpp#L527)), which sometimes results in rendering a partial update.

This can be fixed by e.g. buffering update events and applying them only on `flush`.

<details>

<summary>Example patch on 99d26d355545e7241a0b74586cccd636c88629fc</summary>

```diff
diff --git a/src/gui/shell.cpp b/src/gui/shell.cpp
index f3d3a6e..c19f396 100644
--- a/src/gui/shell.cpp
+++ b/src/gui/shell.cpp
@@ -525,6 +525,18 @@ void Shell::handleSetScrollRegion(const QVariantList& opargs)
 }

 void Shell::handleRedraw(const QByteArray& name, const QVariantList& opargs)
+{
+	if (name == "flush") {
+		for (const auto& cmd : m_pendingRedrawEvents) {
+			handleRedrawEvent(cmd.first, cmd.second);
+		}
+		m_pendingRedrawEvents.clear();
+	} else {
+        m_pendingRedrawEvents.append(qMakePair(name, opargs));
+    }
+}
+
+void Shell::handleRedrawEvent(const QByteArray& name, const QVariantList& opargs)
 {
 	if (name == "update_fg") {
 		if (opargs.size() < 1 || !opargs.at(0).canConvert<quint64>()) {
@@ -621,8 +633,6 @@ void Shell::handleRedraw(const QByteArray& name, const QVariantList& opargs)
 		m_pum.hide();
 	} else if (name == "mode_info_set") {
 		handleModeInfoSet(opargs);
-	} else if (name == "flush") {
-		// Do Nothing, a notification that nvim is done redrawing.
 	} else if (name == "grid_resize") {
 		handleGridResize(opargs);
 	} else if (name == "default_colors_set") {
diff --git a/src/gui/shell.h b/src/gui/shell.h
index 30a108e..27fba5c 100644
--- a/src/gui/shell.h
+++ b/src/gui/shell.h
@@ -142,6 +142,7 @@ protected:
 	virtual void handlePut(const QVariantList& args);
 	virtual void handleHighlightSet(const QVariantMap& args);
 	virtual void handleRedraw(const QByteArray& name, const QVariantList& args);
+	void handleRedrawEvent(const QByteArray& name, const QVariantList& args);
 	virtual void handleScroll(const QVariantList& args);
 	virtual void handleModeChange(const QVariantList& opargs);
 	virtual void handleModeInfoSet(const QVariantList& opargs);
@@ -245,6 +246,8 @@ private:
 	bool m_mouseEnabled{ true };

 	QWindow *m_window_handle{ nullptr };
+
+	QList<QPair<QByteArray, QVariantList>> m_pendingRedrawEvents;
 };

 class ShellRequestHandler: public QObject, public MsgpackRequestHandler
```

</details>
